-- phase 7
-- create revenue view
create view revenue_view as
select 
r.restaurant_id,
r.restaurant_name,
r.city,
sum(o.order_amount - o.discount) as total_revenue
from orders o
join restaurants r on o.restaurant_id = r.restaurant_id
group by r.restaurant_name,r.restaurant_id,r.city;